import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// ============================================================================
// 核心工具库
// ============================================================================

const SmartStr = (defVal = '') =>
  z.preprocess(val => {
    if (val == null || typeof val === 'object') return '';
    return String(val);
  }, z.string()).prefault(defVal);

const SafeNum = (defVal = 0) =>
  z.union([z.number(), z.string(), z.null(), z.undefined()])
    .transform(val => {
      const n = Number(val);
      return isNaN(n) ? defVal : n;
    }).prefault(defVal);

const SmartObj = schema =>
  z.preprocess(val => {
    if (val == null || Array.isArray(val) || typeof val !== 'object') return z.NEVER;
    return val;
  }, schema);

const StatPair = (defCur = 0, defMax = 0) =>
  z.preprocess(
    val => {
      if (val == null) return val;
      if (typeof val === 'number') return { current: val, max: val };
      if (typeof val === 'object') {
        if (val.current === undefined && val.max !== undefined) return { ...val, current: val.max };
        if (val.max === undefined && val.current !== undefined) return { ...val, max: val.current };
      }
      return val;
    },
    z.object({
      current: SafeNum(defCur),
      max: SafeNum(defMax)
    })
  ).transform(d => {
    if (d.current > d.max) d.current = d.max;
    return d;
  }).prefault({ current: defCur, max: defMax });

const AttributeObj = (defVal = 0) => z.object({
  base: SafeNum(defVal),
  total: SafeNum(defVal)
}).prefault({ base: defVal, total: defVal });

// ============================================================================
// 数据结构定义
// ============================================================================

// 物品/装备结构
const ItemSchema = z.object({
  name: SmartStr('未知道具'),
  type: SmartStr('杂物'),
  desc: SmartStr('暂无简介'),
  stats: SmartStr('无'),
  magic_props: z.record(z.string(), SafeNum(0)).prefault({}),
  count: SafeNum(1)
}).partial().transform(d => {
  if (d.type !== '法器' && d.type !== 'Catalyst') {
    delete d.magic_props;
  }
  return _.defaults(d, {
    name: '未命名',
    type: '杂物',
    desc: '暂无简介',
    stats: '无',
    count: 1
  });
});

const EquipmentSlots = SmartObj(z.object({
  MainHand: ItemSchema.nullable().prefault(null),
  OffHand: ItemSchema.nullable().prefault(null),
  Body: ItemSchema.nullable().prefault(null),
  Accessory1: ItemSchema.nullable().prefault(null),
  Accessory2: ItemSchema.nullable().prefault(null),
  Accessory3: ItemSchema.nullable().prefault(null)
}));

// 技能结构 (升级版)
const PassiveSkill = z.object({
  desc: SmartStr('暂无描述'),    // 描述/Flavor
  effect: SmartStr('无')         // 规则效果
});

const ActiveSkill = z.object({
  current: SafeNum(0),           // 当前次数
  max: SafeNum(0),               // 最大次数
  desc: SmartStr('暂无描述'),
  effect: SmartStr('无')
});

const PlayerSchema = SmartObj(z.object({
  Profile: z.object({
    Name: SmartStr('无名氏'),
    Race: SmartStr('人类'),
    Class: SmartStr('冒险者'),
    Age: SmartStr('未知'),
    Gender: SmartStr('未知')
  }).prefault({}),

  Stats: z.object({
    Valor: AttributeObj(0),
    Agility: AttributeObj(0),
    Spirit: AttributeObj(0),
    HP: StatPair(0, 0)
  }).prefault({}),

  Resources: z.object({
    Gold: SafeNum(0),
    HeroPoints: SafeNum(0),
    Exp: SafeNum(0)
  }).prefault({}),

  Combat: z.object({
    Skills: z.object({
      // 改为 Record 结构，键为技能名
      passive: z.record(z.string(), PassiveSkill).prefault({}),
      active: z.record(z.string(), ActiveSkill).prefault({})
    }).prefault({}),
    Equipment: EquipmentSlots
  }).prefault({}),

  Inventory: z.object({
    Backpack: z.record(z.string(), ItemSchema).prefault({})
  }).prefault({})
}));

const WorldSchema = SmartObj(z.object({
  Date: SmartStr('大河历302年 丰收月 1日'),
  Time: SmartStr('清晨'),
  Location: SmartStr('未知区域'),
  DangerLevel: SmartStr('安全')
}));

export const Schema = z.object({
  World: WorldSchema,
  Player: PlayerSchema
});

$(() => {
  registerMvuSchema(Schema);
});

