            font-family: var(--font-display);
            font-size: 1.6em;
            background: linear-gradient(135deg, var(--accent-secondary), var(--accent-color));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            margin-bottom: 15px;
            letter-spacing: 2px;
            font-weight: 600;
        }

        .footer-warning {
            font-size: 0.9em;
            color: #c0b7aa;
            letter-spacing: 3px;
            margin-top: 15px;
        }

        .credits {
            margin-top: 30px;
            padding-top: 20px;
            border-top: 1px solid var(--border-color);
            font-size: 0.9em;
            color: #7a7a7a;
        }

        .credits a {
            color: #66c0f4;
            text-decoration: none;
        }

        .credits a:hover {
            text-decoration: underline;
        }

        /* 响应式 */
        @media (max-width: 768px) {
            .main-container {
                padding: 40px 20px;
            }

            .hero-title {
                font-size: 2.5em;
                letter-spacing: 3px;
            }

            .hero-subtitle {
                font-size: 1em;
                letter-spacing: 2px;
            }

            .welcome-section,
            .lore-section,
            .worldbook-section {
                padding: 35px 25px;
            }

            .welcome-section h2,
            .lore-section h2,
            .options-section h2,
            .worldbook-section h2 {
                font-size: 1.5em;
            }

            .welcome-text,
            .lore-paragraph {
                font-size: 1em;
                line-height: 1.9;
            }

            .worldbook-item {
                flex-direction: column;
                text-align: center;
            }

            .worldbook-marker {
                margin-right: 0;
                margin-bottom: 10px;
            }

            .option-cards {
                grid-template-columns: 1fr;
                gap: 20px;
            }

            .discord-links {
                padding: 20px;
            }
        }

        /* 滚动条样式 */
        ::-webkit-scrollbar {
            width: 10px;
        }

        ::-webkit-scrollbar-track {
            background: var(--body-bg-color);
        }

        ::-webkit-scrollbar-thumb {
            background: linear-gradient(180deg, var(--dark-purple), var(--soft-gold));
            border-radius: 5px;
        }

        ::-webkit-scrollbar-thumb:hover {
            background: linear-gradient(180deg, var(--soft-gold), var(--dark-purple));
