<!DOCTYPE html>
<html>

<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>神帝记 - 角色创造模式 V4.3</title>

  <link rel="preconnect" href="https://unpkg.com">
  <link href="https://unpkg.com/@fontsource/lxgw-wenkai-screen@latest/style.css" rel="stylesheet">
  <link href="https://unpkg.com/@fontsource/noto-serif-sc@latest/400.css" rel="stylesheet">
  <link href="https://unpkg.com/@fontsource/ma-shan-zheng@latest/style.css" rel="stylesheet">

  <style>
    :root {
      /* Base Colors */
      --bg-color: #fcfaf7; /* 卷轴米白色 */
      --text-color: #1a1e27; /* 浓墨黑 */
      --border-color: #c0b7aa; /* 灰土色 */
      --panel-bg-color: #f5f0e9; /* 浅米黄 */
      --accent-color: #5c6c8c; /* 黛青色 */
      --body-bg-color: #1f1d1b; /* 深木纹背景 */
      --shadow-color: rgba(0, 0, 0, 0.15);
      --success-color: #45a049; /* 翠绿色 */
      --danger-color: #dc3545; /* 朱红色 */
      --font-main: 'LXGW WenKai Screen', 'Noto Serif SC', serif;
      --font-display: 'Noto Serif SC', serif;
      --font-decorative: 'Ma Shan Zheng', 'Noto Serif SC', serif; /* 特殊古朴字体 */

      /* New Gemstone Colors */
      --color-moonstone: #8faab9; /* 月长石 */
      --color-emerald: #40b77e; /* 翡翠石翠绿 */
      --color-lapis: #305a9c; /* 青金石苍蓝 */
      --color-amber: #d4994d; /* 琥珀石蜜黄 */
      --color-garnet: #c04848; /* 柘榴石火红 */
      --color-lake: #3cc2e0;   /* 湖蓝色 (伊泰利尔) */

      /* Intro Text Colors */
      --color-dark-purple: #532e8f; /* 肉身, 时间, 遥远前世 */
      --color-soft-gold: #e3b75f; /* 心魂, 因果, 无尽轮回 */

      /* Glow/Shadow */
      --glow-moonstone: 0 0 10px rgba(143, 170, 185, 0.8);
      --glow-emerald: 0 0 10px rgba(64, 183, 126, 0.8);
      --glow-lapis: 0 0 10px rgba(48, 90, 156, 0.8);
      --glow-amber: 0 0 10px rgba(212, 153, 77, 0.8);
      --glow-garnet: 0 0 10px rgba(192, 72, 72, 0.8);
      --glow-scarlet: 0 0 15px #dc3545, 0 0 25px #dc3545; /* 猩红色发光 */
      --glow-lake: 0 0 12px rgba(60, 194, 224, 0.9); /* 湖蓝发光 */
    }

    * {
      box-sizing: border-box;
      transition: background-color 0.2s, border-color 0.2s, box-shadow 0.2s, transform 0.2s, color 0.5s;
    }

    body {
      background: var(--body-bg-color);
      margin: 0;
      font-family: var(--font-main);
      display: flex;
      justify-content: center;
      align-items: flex-start;
      min-height: 100vh;
      padding: 40px 20px;
      color: var(--text-color);
      font-size: 16px; /* 增大基础字体 */
    }

    /* --- 容器/头部/介绍文本样式 --- */
    .creator-container {
      background: var(--bg-color);
      width: 90%;
      max-width: 950px;
      border: 3px solid var(--border-color);
      border-radius: 4px;
      box-shadow: 0 15px 40px var(--shadow-color);
      position: relative;
      z-index: 1;
      text-align: center;
    }

    /* H1 点击区域 */
    .creator-header h1 {
        cursor: pointer;
        margin: 0 0 5px;
        font-size: 2.2em;
        color: var(--color-moonstone);
        font-family: var(--font-display);
        letter-spacing: 2px;
        text-align: center;
        transition: color 0.3s, transform 0.3s;
        user-select: none;
    }
    .creator-header h1:hover { transform: scale(1.02); }

    /* 隐藏模式下的容器样式 */
    .creator-container.secret-active {
        background: var(--body-bg-color);
        border-color: var(--danger-color);
        box-shadow: 0 0 20px rgba(192, 72, 72, 0.6);
        color: var(--color-moonstone) !important; /* 基础文字改为月长石色 */
    }
    .creator-container.secret-active .creator-header, 
    .creator-container.secret-active .form-section {
        background: rgba(0, 0, 0, 0.1); /* 浅黑色面板 */
        border-color: rgba(255, 255, 255, 0.1);
    }

    .creator-header {
      padding: 30px 40px 20px;
      border-bottom: 3px double var(--border-color);
    }

    /* Intro Text Poetic Style */
    .intro-text {
        margin: 10px auto 0;
        max-width: 700px;
        line-height: 1.8;
        padding: 10px 0;
    }
    .intro-text p {
        text-align: center;
        line-height: 2.2;
        font-family: var(--font-main);
        font-size: 1.05em; 
        font-weight: 700; 
    }
    .emphasis-dark {
        color: var(--color-dark-purple);
        font-weight: 900;
        text-shadow: 0 0 1px rgba(0,0,0,0.3);
    }
    .emphasis-light {
        color: var(--color-soft-gold);
        font-weight: 900;
        text-shadow: 0 0 2px rgba(227, 183, 95, 0.5);
    }

    /* --- 表单元素样式 --- */
    .creator-content {
      padding: 30px 40px;
    }

    .form-section {
      margin-bottom: 30px;
      border: 1px solid var(--border-color);
      border-radius: 4px;
      padding: 20px;
      background: var(--panel-bg-color);
      text-align: center;
    }

    /* Section Title Styles (Clickable) */
    .section-title {
      cursor: pointer;
      display: inline-block;
      margin: -35px auto 15px; 
      font-size: 1.35em; 
      padding: 5px 20px;
      background: var(--bg-color); 
      font-family: var(--font-display);
      font-weight: 700;
      border: 2px solid var(--border-color); 
      border-radius: 4px;
      transition: color 0.3s, border-color 0.3s, transform 0.2s;
      user-select: none;
    }
    .form-section[data-section="1"] .section-title { color: var(--color-emerald); border-color: var(--color-emerald); }
    .form-section[data-section="2"] .section-title { color: var(--color-lapis); border-color: var(--color-lapis); }
    .form-section[data-section="3"] .section-title { color: var(--color-amber); border-color: var(--color-amber); }
    .form-section[data-section="4"] .section-title { color: var(--color-garnet); border-color: var(--color-garnet); }
    .section-title:hover { transform: scale(1.02); }

    /* 优化标签样式 - 用同色边框框住 */
    .form-group label {
        display: inline-block;
        padding: 4px 8px;
        margin-bottom: 8px;
        border: 1px solid currentColor;
        border-radius: 4px;
        background-color: rgba(255, 255, 255, 0.7);
        font-weight: 600;
    }

    /* Hidden Text Styles */
    .secret-text {
        font-family: var(--font-decorative);
        font-size: 1.25em;
        font-weight: 700;
        margin: 10px 0 20px 0;
        padding: 8px;
        display: none; 
        text-align: center;
    }
    .secret-text.active {
        display: block;
        animation: pulse-glow 1.5s infinite alternate;
    }

    #secret-text-moonstone, #secret-text-unlocked {
        cursor: pointer;
        margin-top: 5px;
        user-select: none;
    }
    /* 特殊：月长石文本默认不显示，即便是 .active 也要配合逻辑显示 */
    /* 修改为由 JS 控制 display */

    .secret-text.moonstone { color: var(--color-moonstone); text-shadow: var(--glow-moonstone); }
    .secret-text.emerald { color: var(--color-emerald); text-shadow: var(--glow-emerald); }
    .secret-text.lapis { color: var(--color-lapis); text-shadow: var(--glow-lapis); }
    .secret-text.amber { color: var(--color-amber); text-shadow: var(--glow-amber); }
    .secret-text.garnet { color: var(--color-garnet); text-shadow: var(--glow-garnet); }

    /* 新增：伊泰利尔湖蓝样式 */
    .secret-text.italiel {
        color: var(--color-lake);
        text-shadow: var(--glow-lake);
        display: block !important;
    }

    /* Form Alignment */
    .form-group, .form-row {
        text-align: left;
        max-width: 700px;
        margin-left: auto;
        margin-right: auto;
    }

    .form-input, .form-select {
      width: 100%;
      padding: 10px 12px;
      border: 1px solid var(--border-color);
      border-radius: 4px;
      font-size: 1em;
      font-family: var(--font-main);
      background: white;
      color: var(--text-color);
      text-align: left;
    }

    .form-textarea {
      width: 100%;
      padding: 15px 12px;
      min-height: 150px;
      border: 1px solid var(--border-color);
      border-radius: 4px;
      font-size: 1em;
      font-family: var(--font-main);
      background: white;
      color: var(--text-color);
      text-align: left; 
      resize: vertical;
    }

    .form-select:disabled, .form-input:disabled {
        background-color: #e9ecef;
        opacity: 0.65;
    }

    .location-desc-group {
        margin-top: 20px;
        padding-top: 10px;
        border-top: 1px dashed #ccc;
    }
    .description-text {
        font-size: 0.95em;
        color: var(--text-color);
        line-height: 1.6;
        margin-top: 5px;
        padding: 5px 0;
        border-left: none; 
        background: none;
        text-align: left; 
    }
    .description-text.title {
        font-weight: 700;
        margin-top: 10px;
        border-bottom: 1px dotted #ccc;
        padding-bottom: 5px;
        color: var(--accent-color);
    }

    .custom-input-group {
        margin-top: 15px;
        padding-top: 10px;
        border-top: 1px dashed #ccc;
    }

    /* 属性点分配区样式 */
    .attribute-control {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      padding: 15px 10px;
      background: rgba(92, 108, 140, 0.05);
      border: 1px dashed var(--accent-color);
      border-radius: 4px;
      margin-bottom: 15px;
    }

    .attribute-control .label {
      width: auto;
      font-size: 1.1em;
      margin-bottom: 5px;
    }
    .attribute-control .form-label-desc {
        text-align: center;
        margin-left: 0;
        margin-bottom: 10px;
        color: #7a7a7a;
    }
    .attribute-control .controls {
      display: flex;
      align-items: center;
      gap: 15px;
      font-size: 1.0em;
      margin-top: 5px;
    }
    .attribute-control .total-display {
        margin-top: 10px;
        font-size: 1.1em;
        font-weight: 700;
        display: flex;
        align-items: center;
        gap: 5px;
    }
    .attribute-control .total-val {
      font-size: 1.3em;
      padding: 5px 10px;
      background: var(--panel-bg-color);
      border: 1px solid var(--danger-color);
      border-radius: 4px;
      min-width: 40px;
    }

    /* 修复按钮样式，确保显示边框 */
    .adjust-btn {
        width: 32px;
        height: 32px;
        background-color: #fff;
        border: 1px solid var(--border-color);
        border-radius: 4px;
        font-weight: bold;
        font-size: 1.2em;
        cursor: pointer;
        display: flex;
        align-items: center;
        justify-content: center;
        color: var(--text-color);
        transition: all 0.2s;
    }
    .adjust-btn:hover:not(:disabled) {
        background-color: #f0f0f0;
        border-color: var(--accent-color);
    }
    .adjust-btn:disabled {
        opacity: 0.5;
        cursor: not-allowed;
        background-color: #e9ecef;
    }

    #hp-info {
        text-align: center;
        margin-top: 10px;
        padding: 8px;
        border: 1px dashed var(--success-color);
        border-radius: 4px;
        background: rgba(40, 167, 69, 0.05);
        font-weight: 700;
        color: var(--success-color);
    }

    /* 技能选择区域样式 */
    .skills-container {
        margin-top: 20px;
        padding: 15px;
        border: 1px dashed var(--accent-color);
        border-radius: 4px;
        background: rgba(255, 255, 255, 0.5);
    }

    /* 隐藏模式下技能栏背景色 */
    .creator-container.secret-active .skills-container {
        background: rgba(50, 50, 50, 0.5);
    }

    .skill-category {
        margin-bottom: 15px;
        padding: 10px;
        border: 1px solid #ddd;
        border-radius: 4px;
        background: rgba(240, 240, 240, 0.5);
    }

    /* 隐藏模式下技能分类背景色 */
    .creator-container.secret-active .skill-category {
        background: rgba(80, 80, 80, 0.5);
    }

    .skill-category-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        cursor: pointer;
        margin: 0 0 10px 0;
        color: var(--accent-color);
        border-bottom: 1px solid #ccc;
        padding-bottom: 5px;
    }

    .skill-category h4 {
        margin: 0;
        font-size: 1.1em;
    }

    .toggle-icon {
        font-size: 1.2em;
        transition: transform 0.3s;
    }

    .skill-category.collapsed .toggle-icon {
        transform: rotate(-90deg);
    }

    .skill-list {
        max-height: 300px;
        overflow-y: auto;
        padding-right: 5px;
    }

    .skill-category.collapsed .skill-list {
        display: none;
    }

    .skill-option {
        display: flex;
        align-items: flex-start;
        margin-bottom: 12px;
        padding: 8px;
        border-radius: 4px;
        font-size: 1.05em; /* 增大技能字体 */
    }

    .skill-option:hover {
        background: rgba(0, 0, 0, 0.05);
    }

    .skill-option input {
        margin-right: 10px;
        margin-top: 5px;
        transform: scale(1.2); /* 增大复选框 */
    }

    .skill-info {
        flex: 1;
    }

    .skill-name {
        font-weight: bold;
        margin-bottom: 4px;
        font-size: 1.05em;
    }

    .skill-desc {
        color: #666;
        line-height: 1.4;
        font-size: 0.95em;
    }

    .skill-cost {
        font-size: 0.9em;
        color: #888;
        font-style: italic;
        margin-top: 3px;
    }

    .special-skill-notice {
        font-size: 0.9em;
        color: var(--danger-color);
        font-style: italic;
        margin-top: 5px;
    }

    .skill-limit {
        margin-top: 10px;
        font-size: 0.95em;
        color: var(--danger-color);
        font-weight: bold;
    }

    /* 道具区域样式 */
    .items-container {
        margin-top: 20px;
        padding: 15px;
        border: 1px dashed var(--accent-color);
        border-radius: 4px;
        background: rgba(255, 255, 255, 0.5);
    }

    .item-entry {
        margin-bottom: 15px;
        padding: 10px;
        border: 1px solid #ddd;
        border-radius: 4px;
        background: white;
        position: relative;
    }

    .remove-item-btn {
        position: absolute;
        top: 5px;
        right: 5px;
        background: var(--danger-color);
        color: white;
        border: none;
        border-radius: 3px;
        width: 24px;
        height: 24px;
        cursor: pointer;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 0.9em;
    }

    .add-item-btn {
        background: var(--success-color);
        color: white;
        border: none;
        border-radius: 4px;
        padding: 8px 15px;
        cursor: pointer;
        font-size: 0.95em;
        margin-top: 10px;
    }

    .money-info {
        margin-top: 15px;
        padding: 10px;
        border: 1px dashed var(--success-color);
        border-radius: 4px;
        background: rgba(64, 183, 126, 0.1);
        font-weight: bold;
        color: var(--success-color);
    }

    #summary-preview {
      text-align: left;
      white-space: pre-wrap;
      word-wrap: break-word;
      max-height: 400px;
      overflow-y: auto;
      padding: 15px;
      border: 2px solid var(--accent-color);
      background-color: #fff8e1;
      border-radius: 4px;
      font-family: var(--font-main);
    }

    .submit-section {
      margin-top: 30px;
      text-align: center;
    }

    .submit-btn-wrapper {
        text-align: center;
        margin-bottom: 15px;
        position: relative;
    }

    #secret-text-overlay {
        font-family: var(--font-decorative);
        font-size: 1.1em;
        font-weight: 900;
        color: #dc3545;
        text-shadow: var(--glow-scarlet);
        margin-bottom: 15px;
        line-height: 1.5;
        display: none;
    }

    #secret-red-text {
        font-family: var(--font-decorative);
        font-size: 0.9em; /* 小两号字体 */
        font-weight: 700;
        color: #dc3545;
        text-shadow: var(--glow-scarlet);
        margin-top: 15px;
        line-height: 1.5;
        display: none;
    }

    #reset-message {
        font-family: var(--font-display);
        font-size: 1.1em;
        font-weight: 700;
        color: var(--color-moonstone);
        margin-top: 15px;
    }

    .submit-btn {
      padding: 12px 40px;
      font-size: 1.1em;
      font-weight: 700;
      color: white;
      background: linear-gradient(135deg, #7c94a5, var(--color-moonstone));
      border: none;
      border-radius: 6px;
      cursor: pointer;
      box-shadow: 0 4px 15px rgba(143, 170, 185, 0.4);
    }
    .submit-btn:hover:not(:disabled) {
      background: linear-gradient(135deg, #6c8495, #7c94a5);
      transform: translateY(-1px);
    }
    .submit-btn.secret-btn {
        background: linear-gradient(135deg, #a50000, #dc3545) !important;
        box-shadow: var(--glow-scarlet) !important;
        transition: all 0.5s;
    }

    /* 验证信息样式调整 - 移动到预览框下方 */
    .validation-message {
        margin-top: 15px;
        text-align: center;
        font-weight: bold;
    }

    /* --- Secret State Colors Overrides --- */
    /* 隐藏模式下，除了输入框，所有文字都变色 */

    /* 通用月长石色 (头部, 介绍, 通用文本) */
    .creator-container.secret-active h1,
    .creator-container.secret-active .intro-text p,
    .creator-container.secret-active #reset-message,
    .creator-container.secret-active label,
    .creator-container.secret-active .form-label-desc,
    .creator-container.secret-active .description-text,
    .creator-container.secret-active span:not(.total-val):not(.bonus-val):not(.player-val),
    .creator-container.secret-active div:not(.form-input):not(.form-select):not(.form-textarea),
    /* 隐藏模式下区块标题也变色 */
    .creator-container.secret-active .section-title {
        color: var(--color-moonstone) !important;
    }

    /* 区块颜色覆盖 */
    .creator-container.secret-active .form-section[data-section="1"] *:not(.section-title):not(.secret-text):not(.submit-btn):not(.form-input):not(.form-select) {
        color: var(--color-emerald) !important;
    }
    .creator-container.secret-active .form-section[data-section="2"] *:not(.section-title):not(.secret-text):not(.submit-btn):not(.form-input):not(.form-select) {
        color: var(--color-lapis) !important;
    }
    .creator-container.secret-active .form-section[data-section="3"] *:not(.section-title):not(.secret-text):not(.submit-btn):not(.form-input):not(.form-select):not(.form-textarea) {
        color: var(--color-amber) !important;
    }
    .creator-container.secret-active .form-section[data-section="4"] *:not(.section-title):not(.secret-text):not(.submit-btn):not(.form-input):not(.form-select) {
        color: var(--color-garnet) !important;
    }

    /* 保持输入框内部文字为黑色 */
    .creator-container.secret-active .form-input,
    .creator-container.secret-active .form-select,
    .creator-container.secret-active .form-textarea {
        color: var(--text-color) !important;
        background-color: rgba(255, 255, 255, 0.9) !important;
    }
    /* 保持按钮文字白色 */
    .creator-container.secret-active .submit-btn,
    .creator-container.secret-active .adjust-btn {
         color: var(--text-color) !important; /* 调整按钮文字颜色以适应 */
    }
    .creator-container.secret-active .submit-btn {
        color: white !important;
    }

    @media (max-width: 768px) {
      .creator-container { width: 100%; }
      .creator-content, .creator-header { padding: 15px; }
      .form-row, .location-row { grid-template-columns: 1fr; gap: 15px; }
      .attribute-control .controls { justify-content: center; width: 100%; }
      .skill-list { max-height: 200px; }
    }
  </style>
</head>

<body>
  <div class="creator-container">
    <div class="creator-header">
      <h1>神帝记</h1>

      <div id="secret-text-moonstone" class="secret-text moonstone" style="display: none;">月长石尤诺，约定的证明</div>

      <div class="intro-text">
        <p>
          很久很久以前，世界上唯有河流。<br>
          在河流滋润的荒野，<br>
          人类曾盗取魔法，筑起城墙与高塔，<br>
          这是个背叛的故事。<br>
          如今，城墙与高塔虽已崩塌，但艾克薇尔依然流淌。<br>
          寄宿在<span class="emphasis-dark">肉身</span>上的<span class="emphasis-light">心魂</span>啊，<br>
          你正徘徊在死亡边缘，<br>
          但你还不能就此死去。<br>
          即使超脱<span class="emphasis-dark">时间</span>和<span class="emphasis-light">因果</span>，<br>
          你也要回到地上，<br>
          那里还有你不得不去完成的事情。<br>
          你应当偿还<span class="emphasis-light">无尽轮回</span>的扭曲罪孽，<br>
          你应当享受<span class="emphasis-dark">遥远前世</span>的无上荣光。<br>
          欢迎来到"大河世界"——你的故事，将在此重启。
        </p>
      </div>
    </div>

    <div class="creator-content">
      <form id="character-form">

        <div class="form-section" data-section="1">
          <div class="section-title" data-title-id="1">人物出身与身份</div>
          <p id="secret-text-1" class="secret-text emerald">翡翠之席尔巴，<br>让持有者肋生双翼。</p>

          <div class="form-group">
            <label for="char-name">主角名讳</label>
            <input type="text" id="char-name" class="form-input" placeholder="请录入您的角色名" required>
          </div>

          <div class="form-row" style="margin-top: 15px;">
            <div class="form-group">
              <label for="char-gender">性别</label>
              <select id="char-gender" class="form-select" required>
                <option value="男性">男性</option>
                <option value="女性">女性</option>
                <option value="不确定">不确定</option>
              </select>
            </div>
            <div class="form-group">
              <label for="char-age">年龄</label>
              <input type="number" id="char-age" class="form-input" placeholder="年龄" min="1" value="25" required>
            </div>
          </div>

          <div class="form-row" style="margin-top: 15px;">
            <div class="form-group race-class-desc-group">
              <label for="char-race" id="race-label">种族</label> 
              <select id="char-race" class="form-select" required></select>
              <div id="race-desc" class="description-text"></div>
            </div>
            <div class="form-group race-class-desc-group">
              <label for="char-class" id="class-label">职业</label> 
              <select id="char-class" class="form-select" required></select>
              <div id="class-desc" class="description-text"></div>
            </div>
          </div>

          <div id="custom-race-inputs" class="custom-input-group" style="display: none;">
              <div class="form-group">
                <label for="custom-race-name">自定种族名</label>
                <input type="text" id="custom-race-name" class="form-input" placeholder="输入种族名">
              </div>
              <div class="form-group" style="margin-top: 10px;">
                <label for="custom-race-desc">自定种族简介</label>
                <input type="text" id="custom-race-desc" class="form-input" placeholder="输入种族简介">
              </div>
          </div>

          <div id="custom-class-inputs" class="custom-input-group" style="display: none;">
              <div class="form-group">
                <label for="custom-class-name">自定职业名</label>
                <input type="text" id="custom-class-name" class="form-input" placeholder="输入职业名">
              </div>
              <div class="form-group" style="margin-top: 10px;">
                <label for="custom-class-desc">自定职业简介</label>
                <input type="text" id="custom-class-desc" class="form-input" placeholder="输入职业简介">
              </div>
          </div>

          <div class="form-group">
            <label>当前身处区域</label>
            <div class="form-row location-row">
                <div class="form-group">
                  <select id="char-country" class="form-select" required></select>
                </div>
                <div class="form-group">
                  <select id="char-location" class="form-select" required></select>
                </div>
            </div>
            <div class="location-desc-group">
                <div id="country-desc-detail" class="description-text"></div>
                <div id="location-desc-detail" class="description-text"></div>
            </div>
          </div>

          <!-- 新增技能选择区域 -->
          <div class="form-group">
            <label>初始技能选择 (最多3个)</label>
            <div id="skills-container" class="skills-container">
              <!-- 技能将通过JavaScript动态生成 -->
            </div>
            <div class="skill-limit">已选择: <span id="selected-skills-count">0</span>/3 个技能</div>
          </div>

          <!-- 新增道具区域 -->
          <div class="form-group">
            <label>初始道具</label>
            <div id="items-container" class="items-container">
              <!-- 道具将通过JavaScript动态生成 -->
            </div>
            <button type="button" class="add-item-btn" id="add-item-btn">+ 添加道具</button>
            <div class="money-info">初始资金: 50000 G</div>
          </div>
        </div>

        <div class="form-section" data-section="2">
          <div class="section-title" data-title-id="2">核心属性 (总和 9点)</div>
          <p id="secret-text-2" class="secret-text lapis">青金石之费阿，<br>其光辉中凝聚神秘。</p>

          <div id="attributes-container">
            <div class="attribute-control" data-attr="武勇">
              <span class="label">武勇</span>
              <span class="form-label-desc">表现出"有多像战士"的能力。</span>
              <div class="controls">
                <span class="bonus-val" data-race-bonus>+0</span>
                <span class="bonus-val" data-class-bonus>+0</span>
                <span class="player-val" data-player>0</span>
              </div>
              <div class="controls" style="margin-top: 10px; border-top: 1px dotted #ccc; padding-top: 10px;">
                <button type="button" class="adjust-btn minus-btn">-</button>
                <button type="button" class="adjust-btn plus-btn">+</button>
              </div>
              <div class="total-display">
                  <span style="color: var(--danger-color);">总值:</span>
                  <span class="total-val" data-total>0</span>
              </div>
            </div>

            <div class="attribute-control" data-attr="机敏">
              <span class="label">机敏</span>
              <span class="form-label-desc">表现出"行动有多敏捷"的能力。</span>
              <div class="controls">
                <span class="bonus-val" data-race-bonus>+0</span>
                <span class="bonus-val" data-class-bonus>+0</span>
                <span class="player-val" data-player>0</span>
              </div>
              <div class="controls" style="margin-top: 10px; border-top: 1px dotted #ccc; padding-top: 10px;">
                <button type="button" class="adjust-btn minus-btn">-</button>
                <button type="button" class="adjust-btn plus-btn">+</button>
              </div>
              <div class="total-display">
                  <span style="color: var(--danger-color);">总值:</span>
                  <span class="total-val" data-total>0</span>
              </div>
            </div>

            <div class="attribute-control" data-attr="精神">
              <span class="label">精神</span>
              <span class="form-label-desc">表现出"意志有多坚定"的能力。</span>
              <div class="controls">
                <span class="bonus-val" data-race-bonus>+0</span>
                <span class="bonus-val" data-class-bonus>+0</span>
                <span class="player-val" data-player>0</span>
              </div>
              <div class="controls" style="margin-top: 10px; border-top: 1px dotted #ccc; padding-top: 10px;">
                <button type="button" class="adjust-btn minus-btn">-</button>
                <button type="button" class="adjust-btn plus-btn">+</button>
              </div>
              <div class="total-display">
                  <span style="color: var(--danger-color);">总值:</span>
                  <span class="total-val" data-total>0</span>
              </div>
            </div>
          </div>

          <div id="hp-info">最大生命值 (HP): <span id="max-hp-value">20</span></div>
        </div>

        <div class="form-section" data-section="3">
          <div class="section-title" data-title-id="3">人物形貌与心性</div>
          <p id="secret-text-3" class="secret-text amber">琥珀之艾尔雅，<br>让持有者意如钢铁。</p>
          <div class="form-group">
            <label for="char-description">形貌描述 <span class="form-label-desc">(您的外表、穿着、体型等)</span></label>
            <textarea id="char-description" class="form-textarea" placeholder="您可以在此输入自定义的外貌描述，如果留空，角色卡预览将显示该职业的默认外貌描述。"></textarea>
          </div>
          <div class="form-group">
            <label for="char-background">心性与过往 <span class="form-label-desc">(您的目标、性格标签、一段简短的背景故事)</span></label>
            <textarea id="char-background" class="form-textarea" placeholder="您可以在此输入自定义的背景故事，如果留空，角色卡预览将显示该职业的默认背景故事。"></textarea>
          </div>
          <div class="form-group">
            <label for="char-start-story">开局故事 <span class="form-label-desc">(您的角色即将开始的故事场景)</span></label>
            <textarea id="char-start-story" class="form-textarea" placeholder="您可以在此输入自定义的开局故事，如果留空，角色卡预览将显示该职业的默认开局故事。若对如何进行剧情感到迷茫，可以选择以默认剧情开局或是进行删改，不同职业的默认剧情不同，可自由选择。"></textarea>
          </div>
        </div>

        <div class="form-section" data-section="4">
          <div class="section-title" data-title-id="4">角色卡预览</div>
