      // --- 新增函数：道具系统 ---

      // 初始化道具系统
      function initItems() {
        itemsContainer.innerHTML = '';
        itemCounter = 0;
        addItem(); // 添加第一个道具栏
      }

      // 添加道具栏
      function addItem() {
        itemCounter++;
        const itemEntry = document.createElement('div');
        itemEntry.className = 'item-entry';
        itemEntry.dataset.itemId = itemCounter;

        const removeBtn = document.createElement('button');
        removeBtn.type = 'button';
        removeBtn.className = 'remove-item-btn';
        removeBtn.innerHTML = '×';
        removeBtn.title = '删除此道具';
        removeBtn.addEventListener('click', function() {
          itemEntry.remove();
          updateSummary();
        });

        const itemNameInput = document.createElement('input');
        itemNameInput.type = 'text';
        itemNameInput.className = 'form-input';
        itemNameInput.placeholder = '道具名称';
        itemNameInput.addEventListener('input', updateSummary);

        const itemDescTextarea = document.createElement('textarea');
        itemDescTextarea.className = 'form-textarea';
        itemDescTextarea.placeholder = '道具效果描述';
        itemDescTextarea.style.minHeight = '60px';
        itemDescTextarea.addEventListener('input', updateSummary);

        itemEntry.appendChild(removeBtn);
        itemEntry.appendChild(itemNameInput);
        itemEntry.appendChild(itemDescTextarea);

        itemsContainer.appendChild(itemEntry);
      }

      // 获取道具信息
      function getItemsInfo() {
        const items = [];
        const itemEntries = itemsContainer.querySelectorAll('.item-entry');

        itemEntries.forEach(entry => {
          const nameInput = entry.querySelector('input');
          const descTextarea = entry.querySelector('textarea');

          if (nameInput.value.trim()) {
            items.push({
              name: nameInput.value.trim(),
              description: descTextarea.value.trim()
            });
          }
        });

        return items;
      }

      // --- 新增函数：技能系统 ---

      // 渲染技能选择界面
      function renderSkills() {
        skillsContainer.innerHTML = '';
        const currentRace = charRace.value;

        Object.keys(SKILLS).forEach(category => {
          const categoryDiv = document.createElement('div');
          categoryDiv.className = 'skill-category';

          const categoryHeader = document.createElement('div');
          categoryHeader.className = 'skill-category-header';

          const categoryTitle = document.createElement('h4');
          categoryTitle.textContent = category;

          const toggleIcon = document.createElement('span');
          toggleIcon.className = 'toggle-icon';
          toggleIcon.innerHTML = '▼';
          toggleIcon.style.cursor = 'pointer';

          categoryHeader.appendChild(categoryTitle);
          categoryHeader.appendChild(toggleIcon);
          categoryDiv.appendChild(categoryHeader);

          // 添加特殊系技能提示
          if (category === '特殊系') {
            const specialNotice = document.createElement('div');
            specialNotice.className = 'special-skill-notice';
            specialNotice.textContent = '※ 特殊系技能仅限特定种族学习';
            categoryDiv.appendChild(specialNotice);
          }

          const skillList = document.createElement('div');
          skillList.className = 'skill-list';

          SKILLS[category].forEach(skill => {
            // 检查种族限制
            if (skill.allowedRaces && !skill.allowedRaces.includes(currentRace)) {
              return; // 跳过不符合种族条件的技能
            }

            const skillOption = document.createElement('div');
            skillOption.className = 'skill-option';

            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.id = `skill-${skill.id}`;
            checkbox.value = skill.id;
            checkbox.checked = selectedSkills.has(skill.id);
            checkbox.disabled = !checkbox.checked && selectedSkills.size >= MAX_SKILLS;

            checkbox.addEventListener('change', function() {
              if (this.checked) {
                if (selectedSkills.size < MAX_SKILLS) {
                  selectedSkills.add(skill.id);
                } else {
                  this.checked = false;
                  validationMsg.textContent = `❌ 最多只能选择 ${MAX_SKILLS} 个技能！`;
                  validationMsg.style.color = 'var(--danger-color)';
                  setTimeout(() => validationMsg.textContent = '', 3000);
                  return;
                }
              } else {
                selectedSkills.delete(skill.id);
              }

              updateSkillSelection();
              updateSummary();
            });

            const skillInfo = document.createElement('div');
            skillInfo.className = 'skill-info';

            const skillName = document.createElement('div');
            skillName.className = 'skill-name';
            skillName.textContent = skill.name;

            const skillDesc = document.createElement('div');
            skillDesc.className = 'skill-desc';
            skillDesc.textContent = skill.description;

            const skillCost = document.createElement('div');
            skillCost.className = 'skill-cost';
            skillCost.textContent = `类型: ${skill.costType}`;

            skillInfo.appendChild(skillName);
            skillInfo.appendChild(skillDesc);
            skillInfo.appendChild(skillCost);

            skillOption.appendChild(checkbox);
            skillOption.appendChild(skillInfo);

            skillList.appendChild(skillOption);
          });

          categoryDiv.appendChild(skillList);

          // 添加折叠功能
          categoryHeader.addEventListener('click', function() {
            categoryDiv.classList.toggle('collapsed');
          });

          skillsContainer.appendChild(categoryDiv);
        });
      }

      // 更新技能选择状态
      function updateSkillSelection() {
        selectedSkillsCount.textContent = selectedSkills.size;

        // 更新所有复选框的禁用状态
        document.querySelectorAll('#skills-container input[type="checkbox"]').forEach(checkbox => {
          checkbox.disabled = !checkbox.checked && selectedSkills.size >= MAX_SKILLS;
        });
      }

      // 获取选中的技能信息
      function getSelectedSkillsInfo() {
        const skillsInfo = [];

        selectedSkills.forEach(skillId => {
          // 在所有分类中查找技能
          for (const category in SKILLS) {
            const skill = SKILLS[category].find(s => s.id === skillId);
            if (skill) {
              skillsInfo.push(skill);
              break;
            }
          }
        });

        return skillsInfo;
      }

      // 获取职业默认数据
      function getClassDefaultData(className) {
        return CLASS_DEFAULT_DATA[className] || CLASS_DEFAULT_DATA['自定'];
      }

      function getTotalFreePoints() {
        let total = MAX_FREE_POINTS;
        if (charRace.value === '自定') total += RACE_CUSTOM_BONUS;
        if (charClass.value === '自定') total += CLASS_CUSTOM_BONUS;
        if (whiteChildUnlocked) total += 1;
        return total;
      }

      function populateSelects() {
        charRace.innerHTML = '';
        for (const race in RACE_BONUSES) {
          if (race === WHITE_CHILD_NAME) continue;
          const option = document.createElement('option');
          option.value = race;
          option.textContent = race;
          charRace.appendChild(option);
        }
        const customRaceOption = Array.from(charRace.options).find(opt => opt.value === '自定');
        if (customRaceOption) charRace.appendChild(customRaceOption);

        charClass.innerHTML = '';
        for (const classN in CLASS_BONUSES) {
          if (classN === '自定') continue;
          const option = document.createElement('option');
          option.value = classN;
          option.textContent = classN;
          charClass.appendChild(option);
        }
        const customClassOption = document.createElement('option');
        customClassOption.value = '自定';
        customClassOption.textContent = '自定';
        charClass.appendChild(customClassOption);

        charCountry.innerHTML = ''; 
        LOCATION_ORDER.forEach(country => {
          const option = document.createElement('option');
          option.value = country;
          let text = country;
          if (LOCATION_DATA[country].incomplete && country !== '独立阵营' && country !== '无所属') {
              option.classList.add('red-circle');
          }
          option.textContent = text;
          charCountry.appendChild(option);
        });
      }

      function populateSecretClasses() {
          const allowedClasses = ['骑士', '盗贼', '贤者', '神官'];
          charClass.innerHTML = '';
          allowedClasses.forEach(className => {
               const option = document.createElement('option');
               option.value = className;
               option.textContent = className;
               charClass.appendChild(option);
          });
          if (!allowedClasses.includes(charClass.value)) {
              charClass.value = allowedClasses[0];
          }
      }

      function toggleCustomInputs() {
          if (charRace.value === '自定') {
              customRaceInputs.style.display = 'block';
              raceDesc.textContent = `${RACE_BONUSES[charRace.value].desc}`;
          } else {
              customRaceInputs.style.display = 'none';
              const raceData = RACE_BONUSES[charRace.value];
              raceDesc.textContent = `${raceData ? raceData.desc : '无描述'}`;
          }

          if (charClass.value === '自定') {
              customClassInputs.style.display = 'block';
              classDesc.textContent = `${CLASS_BONUSES[charClass.value].desc}`;
          } else {
              customClassInputs.style.display = 'none';
              const classData = CLASS_BONUSES[charClass.value];
              classDesc.textContent = `${classData ? classData.desc : '无描述'}`;
          }
      }

      const getModifier = (stat) => Math.floor((stat - 10) / 2);

      function adjustAttribute(attr, amount) {
        const allocated = currentAllocated[attr]; 
        const totalFreePoints = getTotalFreePoints();

        if (amount > 0 && remainingPoints <= 0) {
          validationMsg.textContent = '❌ 玩家自定点数已用尽！';
          setTimeout(() => validationMsg.textContent = '', 2000);
          return;
        }

        if (amount > 0 && (allocated + amount) > totalFreePoints) {
            validationMsg.textContent = `❌ 单项属性玩家分配点数已超过总自由点数 ${totalFreePoints}！`;
            setTimeout(() => validationMsg.textContent = '', 2000);
            return;
        }

        if (amount < 0 && (allocated + amount) < 0) return;

        currentAllocated[attr] += amount;
        remainingPoints -= amount;

        updateAllAttributes();
        updateSummary();
      }

      function updateAllAttributes() {
        const selectedRace = charRace.value;
        const selectedClass = charClass.value;
        const totalFreePoints = getTotalFreePoints();

        remainingPointsSpan.textContent = remainingPoints;

        const actualRace = whiteChildUnlocked ? WHITE_CHILD_NAME : selectedRace;
        const raceDataForBonus = (actualRace === WHITE_CHILD_NAME) ? RACE_BONUSES['示巴人'] : RACE_BONUSES[selectedRace];

        let finalSTR = 0;

        ATTRIBUTES.forEach(attr => {
          const allocated = currentAllocated[attr];
          const raceBonus = raceDataForBonus[attr] || 0; 
          const classBonus = CLASS_BONUSES[selectedClass][attr] || 0;
          const finalStat = raceBonus + classBonus + allocated; 

          if (attr === '武勇') finalSTR = finalStat;

          attributeElements[attr].player.textContent = allocated;
          attributeElements[attr].raceBonus.textContent = raceBonus > 0 ? `+${raceBonus}` : raceBonus;
          attributeElements[attr].classBonus.textContent = classBonus > 0 ? `+${classBonus}` : classBonus;
          attributeElements[attr].total.textContent = finalStat;

          const plusBtn = attributeElements[attr].element.querySelector('.plus-btn');
          const minusBtn = attributeElements[attr].element.querySelector('.minus-btn');

          if (allocated >= totalFreePoints || remainingPoints <= 0) {
            plusBtn.disabled = true;
          } else {
            plusBtn.disabled = false;
          }

          if (allocated <= 0) {
            minusBtn.disabled = true;
          } else {
            minusBtn.disabled = false;
          }
        });

        const strModifier = getModifier(finalSTR);
        const maxHP = BASE_HP + strModifier;
        maxHpValueSpan.textContent = `${maxHP} (基础 ${BASE_HP} + 武勇修正值 ${strModifier > 0 ? '+' : ''}${strModifier})`;

        if (remainingPoints <= 0) {
           validationMsg.textContent = `✅ 点数已用尽，属性总和为 ${totalFreePoints}，可开始创作。`;
           validationMsg.style.color = 'var(--success-color)';
        } else {
           validationMsg.textContent = `您还剩余 ${remainingPoints} 点可自由分配。 (总点数: ${totalFreePoints})`;
           validationMsg.style.color = 'var(--danger-color)';
        }
      }

      function updateCitySelect() {
          const country = charCountry.value;
          const data = LOCATION_DATA[country];

          countryDescDetail.textContent = data.desc;
          countryDescDetail.classList.add('description-text', 'title');

          charLocation.innerHTML = '';
          let cityDescription = '';

          if (secretTriggered) {
               charLocation.innerHTML = `<option value="${SECRET_LOCATION}">${SECRET_LOCATION}</option>`;
               charLocation.value = SECRET_LOCATION;
               cityDescription = HOLMTOWN_SECRET_DESC;
               countryDescDetail.textContent = LOCATION_DATA[SECRET_COUNTRY].desc; 
          } else {
              Object.keys(data.cities).forEach(city => {
                  const option = document.createElement('option');
                  option.value = city;
                  option.textContent = city;
                  charLocation.appendChild(option);
              });
              charLocation.value = Object.keys(data.cities)[0]; 
              cityDescription = data.cities[charLocation.value] || '';
          }

          locationDescDetail.textContent = `[${charLocation.value}]: ${cityDescription}`;
          locationDescDetail.classList.add('description-text');

          updateSummary();
      }

      function triggerSecretState() {
          secretTriggered = true;
          document.querySelector('.creator-container').classList.add('secret-active');

          secretTextMoonstone.style.display = 'none';
          secretTextMoonstone.textContent = '月长石尤诺，约定的证明'; 
          secretTextMoonstone.className = 'secret-text moonstone';

          resetMessage.style.display = 'none'; 
          secretTextOverlay.style.display = 'block'; 
          secretRedText.style.display = 'block';

          charCountry.value = SECRET_COUNTRY;
          charCountry.disabled = true;
          updateCitySelect();
          charLocation.disabled = true;

          charRace.innerHTML = `<option value="示巴人">示巴人</option>`;
          charRace.value = '示巴人';
          charRace.disabled = true;
          raceDesc.textContent = `${RACE_BONUSES['示巴人'].desc}`;
          customRaceInputs.style.display = 'none'; 

          populateSecretClasses();
          charClass.disabled = false;
          classDesc.textContent = `${CLASS_BONUSES[charClass.value].desc}`;
          customClassInputs.style.display = 'none';

          charAge.value = 18;
          charAge.disabled = true;

          resetPoints();

          submitBtn.textContent = '踏入奈落之底';
          submitBtn.classList.add('secret-btn');
          validationMsg.textContent = '你将前往奈落之底，探寻血脉的真相';
          validationMsg.style.color = 'var(--color-garnet)';

          updateAllAttributes();
          updateSummary(); 

          // 更新技能显示
          renderSkills();
      }

      function unlockWhiteChild() {
          if (whiteChildUnlocked) return;
          whiteChildUnlocked = true;

          const shibaOption = charRace.querySelector('option[value="示巴人"]');
          if (shibaOption) shibaOption.textContent = WHITE_CHILD_NAME;

          raceDesc.textContent = `${WHITE_CHILD_DESC}`;
          raceLabel.textContent = `种族 (${WHITE_CHILD_NAME} - 奖励点+1!)`;

          resetPoints();
          updateAllAttributes();
          updateSummary();

          validationMsg.textContent = '🎉 隐藏种族"白子族"已解锁！额外获得 1 点自由分配点数。';
          validationMsg.style.color = 'var(--success-color)';
          setTimeout(() => validationMsg.textContent = '', 5000);
      }

      function resetSecretState() {
          if (!secretTriggered) return; 

          secretTriggered = false;
          document.querySelector('.creator-container').classList.remove('secret-active');
          secretCount = 4; 

          secretTextMoonstone.textContent = '光辉之伊泰利尔，爱人还是母亲？';
          secretTextMoonstone.className = 'secret-text italiel active';
          secretTextMoonstone.style.display = 'block';

          secretTextOverlay.style.display = 'none';
          secretRedText.style.display = 'none';

          charRace.disabled = false;
          charClass.disabled = false;
          charAge.disabled = false;
          charAge.value = 25;

          if (whiteChildUnlocked) {
              whiteChildUnlocked = false; 
              raceLabel.textContent = `种族`; 
          }
          raceClickCount = 0;

          populateSelects(); 

          charCountry.disabled = false;
          charLocation.disabled = false;
          charCountry.value = '东示巴王国';
          charRace.value = '拉克森人';
          charClass.value = '斗士';
          updateCitySelect();

          toggleCustomInputs(); 

          submitBtn.textContent = '启程入世';
          submitBtn.classList.remove('secret-btn');
          validationMsg.textContent = ''; 
          resetMessage.style.display = 'block';

          resetPoints();
          updateAllAttributes();
          updateSummary(); 

          // 更新技能显示
          renderSkills();
      }

      function generateSummaryText() {
        const name = charName.value.trim() || '未命名';
        const gender = charGender.value;
        const age = charAge.value;

        const finalAttributes = {};
        const totalFreePoints = getTotalFreePoints();

        const isCustomRace = charRace.value === '自定';
        const isCustomClass = charClass.value === '自定';
        const actualRace = whiteChildUnlocked ? WHITE_CHILD_NAME : (isCustomRace ? customRaceName.value.trim() || '自定种族' : charRace.value);
        const charClassVal = isCustomClass ? customClassName.value.trim() || '自定职业' : charClass.value;

        // 分别检查三个输入框是否为空
        const userDescription = charDescription.value.trim();
        const userBackground = charBackground.value.trim();
        const userStartStory = charStartStory.value.trim();

        // 获取职业默认数据
        const classData = getClassDefaultData(charClass.value);

        // 决定使用用户输入还是默认值
        const description = userDescription ? userDescription : classData.description;
        const background = userBackground ? userBackground : classData.background;
        const startStory = userStartStory ? userStartStory : classData.startStory;

        const raceDataForSummary = isCustomRace ? RACE_BONUSES['自定'] : (whiteChildUnlocked ? RACE_BONUSES['示巴人'] : RACE_BONUSES[charRace.value]);
        const classDataForSummary = isCustomClass ? CLASS_BONUSES['自定'] : CLASS_BONUSES[charClass.value];

        const raceDescSummary = isCustomRace ? (customRaceDesc.value.trim() || '未设定自定种族简介') : (whiteChildUnlocked ? WHITE_CHILD_DESC : RACE_BONUSES[charRace.value].desc);
        const classDescSummary = isCustomClass ? (customClassDesc.value.trim() || '未设定自定职业简介') : CLASS_BONUSES[charClass.value].desc;

        ATTRIBUTES.forEach(attr => {
          finalAttributes[attr] = parseInt(attributeElements[attr].total.textContent);
        });

        const strModifier = getModifier(finalAttributes['武勇']);
        const maxHP = BASE_HP + strModifier;

        // 计算属性总和
        const totalAttributes = finalAttributes['武勇'] + finalAttributes['机敏'] + finalAttributes['精神'];

        const country = charCountry.value;
        const location = charLocation.value;
        const countryData = LOCATION_DATA[country];
        const cityDescription = secretTriggered && location === SECRET_LOCATION 
            ? HOLMTOWN_SECRET_DESC 
            : countryData.cities[location] || '（未知区域）';

        // 获取技能信息
        const selectedSkillsInfo = getSelectedSkillsInfo();
        const itemsInfo = getItemsInfo();

        let summary = `【人物档案：${name}】\n\n`;
        summary += `◇ 基础信息: ${gender} / ${age}岁 / ${actualRace} / ${charClassVal} \n`; 
        summary += `◇ 种族简介: ${raceDescSummary}\n`;
        summary += `◇ 职业简介: ${classDescSummary}\n`;
        summary += `◇ 出身区域: ${country} - ${location}\n`;
        summary += `   (区域简介: ${cityDescription})\n\n`;

        summary += `【核心属性】 (总和 ${totalAttributes}点)\n`;
        ATTRIBUTES.forEach(attr => {
          summary += ` ${attr}: ${finalAttributes[attr]}\n`;
        });
        summary += `\n`;

        summary += `【衍生信息】\n`;
        summary += `◇ 最大生命值 (HP): ${maxHP}\n`;
        summary += `◇ 初始资金: 50000 G\n\n`;

        // 新增技能信息
        summary += `【初始技能】 (${selectedSkillsInfo.length}/3)\n`;
        if (selectedSkillsInfo.length > 0) {
          selectedSkillsInfo.forEach(skill => {
            summary += ` ◇ ${skill.name} (${skill.costType}): ${skill.description}\n`;
          });
        } else {
          summary += ` 无初始技能\n`;
        }
        summary += `\n`;

        // 新增道具信息
        summary += `【初始道具】\n`;
        if (itemsInfo.length > 0) {
          itemsInfo.forEach(item => {
            summary += ` ◇ ${item.name}: ${item.description}\n`;
          });
        } else {
          summary += ` 无初始道具\n`;
        }
        summary += `\n`;

        summary += `【形貌与心性】\n`;
        summary += `◇ 形貌描述: ${description}\n\n`;
        summary += `◇ 心性与过往: ${background}\n\n`;

        // 新增起始情景和任务
        summary += `【开局故事】\n`;
        summary += `${startStory}\n\n`;

        summary += `========================================\n`;
        if (secretTriggered) {
          summary += `GM: **[警告]** 核心暗线被激活！你来到了小镇地底的洞窟，似乎有什么东西在隐隐呼唤着你，但你却不知道那是什么。\n`;
        } else {
          summary += `GM: 请严格遵循上述【人物档案】、【核心属性】和【衍生信息】进行开场和后续判定。\n`;
        }
        summary += `游戏规则采用"大河物语"TRPG规则（如：判定为 属性值 + 2D6 + 修正值）。\n`;
        summary += `请在故事中自然地融入角色的出身背景、性格特点、经历和当前状态；在设置变量时，请你使用UpdateVariable修改未设置的变量，使其符合人物档案。当前时间为王国历302年，请以第三人称视角开始游戏。`;

        return summary;
      }

      function updateSummary() {
        summaryPreview.textContent = generateSummaryText();
      }

      function resetPoints() {
            remainingPoints = getTotalFreePoints();
            ATTRIBUTES.forEach(attr => {
                currentAllocated[attr] = 0;
            });
      }

      // 简化的复制功能
      function copyToClipboard() {
        const text = generateSummaryText();

        // 使用现代 Clipboard API
        if (navigator.clipboard && window.isSecureContext) {
          navigator.clipboard.writeText(text).then(() => {
            validationMsg.textContent = '✅ 角色卡已复制到剪贴板！';
            validationMsg.style.color = 'var(--success-color)';
            setTimeout(() => validationMsg.textContent = '', 3000);
          }).catch(err => {
            console.error('复制失败:', err);
            fallbackCopyTextToClipboard(text);
          });
        } else {
          // 回退方案
          fallbackCopyTextToClipboard(text);
        }
      }

      // 回退复制方案
      function fallbackCopyTextToClipboard(text) {
        const textArea = document.createElement("textarea");
        textArea.value = text;
        textArea.style.position = "fixed";
        textArea.style.left = "-999999px";
        textArea.style.top = "-999999px";
        document.body.appendChild(textArea);
        textArea.focus();
        textArea.select();

        try {
          document.execCommand('copy');
          validationMsg.textContent = '✅ 角色卡已复制到剪贴板！(兼容模式)';
          validationMsg.style.color = 'var(--success-color)';
          setTimeout(() => validationMsg.textContent = '', 3000);
        } catch (err) {
          console.error('回退复制失败:', err);
          validationMsg.textContent = '❌ 复制失败，请手动复制预览框内容';
          validationMsg.style.color = 'var(--danger-color)';
        }

        document.body.removeChild(textArea);
      }

      function setupTitleListeners() {
        document.querySelectorAll('.section-title').forEach(title => {
            const titleId = parseInt(title.dataset.titleId);
            const secretTextEl = document.getElementById(`secret-text-${titleId}`);

            title.addEventListener('click', () => {
                if (secretTextEl.classList.contains('active')) return;

                secretTextEl.classList.add('active');
                secretCount++;

                if (secretCount === 4 && !secretTriggered) {
                    triggerSecretState();
                }
            });
        });

        // H1 标题监听器：
        document.querySelector('.creator-header h1').addEventListener('click', () => {
            if (secretTriggered) {
                // 隐藏模式下：切换显示/隐藏月长石文本
                if (secretTextMoonstone.style.display === 'none') {
                    secretTextMoonstone.style.display = 'block';
                    secretTextMoonstone.classList.add('active');
                } else {
                    secretTextMoonstone.style.display = 'none';
                    secretTextMoonstone.classList.remove('active');
                }
            } else {
                // 普通模式下：显示"还不是时候"
                resetMessage.style.display = 'block'; 
            } 
        });

        // 月长石重置监听器：点击后变为伊泰利尔并重置界面
        secretTextMoonstone.addEventListener('click', () => {
            if (secretTriggered) {
                resetSecretState(); 
            }
        });
    }

      function setupListeners() {
          attributesContainer.querySelectorAll('.attribute-control').forEach(control => {
            const attr = control.dataset.attr;
            attributeElements[attr] = {
              raceBonus: control.querySelector('[data-race-bonus]'),
              classBonus: control.querySelector('[data-class-bonus]'),
              player: control.querySelector('[data-player]'),
              total: control.querySelector('[data-total]'),
              element: control
            };

            control.querySelector('.plus-btn').addEventListener('click', () => adjustAttribute(attr, 1));
            control.querySelector('.minus-btn').addEventListener('click', () => adjustAttribute(attr, -1));
          });

          [charName, charGender, charAge, charDescription, charBackground, charStartStory, customRaceName, customRaceDesc, customClassName, customClassDesc].forEach(el => {
            el.addEventListener('input', updateSummary);
            el.addEventListener('change', updateSummary);
          });

          // 道具添加按钮监听
          addItemBtn.addEventListener('click', addItem);

          charRace.addEventListener('change', () => {
              if (secretTriggered) return; 
              resetPoints();
              toggleCustomInputs();
              updateAllAttributes();
              updateSummary();
              // 更新技能显示
              renderSkills();
          });

          charClass.addEventListener('change', () => {
              if (!secretTriggered) resetPoints(); 
              toggleCustomInputs();
              updateAllAttributes();
              updateSummary();
          });

          charCountry.addEventListener('change', () => {
              if (secretTriggered) return; 
              updateCitySelect(); 
          });

          charLocation.addEventListener('change', () => {
              if (secretTriggered) return; 
              const country = charCountry.value;
              const city = charLocation.value;
              const data = LOCATION_DATA[country];
              const cityDesc = data.cities[city] || '';

              locationDescDetail.textContent = `[${city}]: ${cityDesc}`;
              updateSummary();
          });

          raceLabel.addEventListener('click', () => {
              if (secretTriggered && charRace.value === '示巴人' && !whiteChildUnlocked) {
                  raceClickCount++;
                  if (raceClickCount >= 16) {
                      unlockWhiteChild();
                  }
              }
          });

          // 修改提交按钮功能：改为复制文本
          submitBtn.addEventListener('click', copyToClipboard);
      }

      const initialSetup = () => {
          populateSelects();
          setupListeners();
          setupTitleListeners();

          // 设置默认值
          charGender.value = '男性';
          charAge.value = 25; 
          charRace.value = '示巴人';
          charClass.value = '斗士';

          // 清空三个文本输入框，让它们保持空白
          charDescription.value = '';
          charBackground.value = '';
          charStartStory.value = '';

          toggleCustomInputs(); 
          raceDesc.textContent = `${RACE_BONUSES[charRace.value].desc}`;
          classDesc.textContent = `${CLASS_BONUSES[charClass.value].desc}`;
          charCountry.value = '东示巴王国';
          updateCitySelect();

          resetPoints();
          updateAllAttributes();

          // 初始化技能显示
          renderSkills();

          // 初始化道具系统
          initItems();

          updateSummary();
      };

      initialSetup();
    })();
  </script>
</body>

