  <div class="battle-status-bar">
    <div class="battle-title">[ 战斗状态 ]</div>
    <div class="turn-info" id="turnInfo">$1</div>
    <div class="character-grid" id="characterGrid">
      <!-- 角色卡片将通过JavaScript动态生成 -->
    </div>
  </div>

  <script>
    function parseCharacterData(text) {
      const characters = [];
      const characterRegex = /\[([^\]]+)\]: HP (\d+)\/(\d+) \[状态: ([^\]]+)\]/g;
      let match;

      while ((match = characterRegex.exec(text)) !== null) {
        const name = match[1];
        const currentHP = parseInt(match[2]);
        const maxHP = parseInt(match[3]);
        const statusText = match[4];

        const hpPercentage = (currentHP / maxHP) * 100;
        let hpLevel = 'high';
        if (hpPercentage <= 25) hpLevel = 'low';
        else if (hpPercentage <= 60) hpLevel = 'medium';

        const isEnemy = name.toLowerCase().includes('enemy') || 
                       name.includes('敌人') || 
                       !name.includes('<user>');

        const statusEffects = statusText.split(/[,，]/).map(s => s.trim()).filter(s => s);

        characters.push({
          name,
          currentHP,
          maxHP,
          hpPercentage,
          hpLevel,
          isEnemy,
          statusEffects
        });
      }

      return characters;
    }

    function createCharacterCard(character) {
      const card = document.createElement('div');
      card.className = 'character-card';

      const nameClass = character.isEnemy ? 'enemy-name' : 'player-name';
      const hpClass = `hp-${character.hpLevel}`;

      card.innerHTML = `
        <div class="character-header">
          <span class="character-name ${nameClass}">${character.name}</span>
          <span class="hp-display">HP: ${character.currentHP}/${character.maxHP}</span>
        </div>
        <div class="hp-bar-container">
          <div class="hp-bar ${hpClass}" style="width: ${character.hpPercentage}%"></div>
        </div>
        ${character.statusEffects.length > 0 ? `
          <div class="status-effects">
            ${character.statusEffects.map(status => 
              `<span class="status-tag ${getStatusClass(status)}">${status}</span>`
            ).join('')}
          </div>
        ` : ''}
      `;

      return card;
    }

    function getStatusClass(status) {
      const positive = ['治疗', '增益', '强化', '正常', 'heal', 'buff', 'boost'];
      const negative = ['轻伤', '重伤', '中毒', '眩晕', '失去平衡', 'wound', 'poison', 'stun'];

      if (positive.some(p => status.includes(p))) return 'status-positive';
      if (negative.some(n => status.includes(n))) return 'status-negative';
      return 'status-neutral';
    }

    // 初始化
    document.addEventListener('DOMContentLoaded', function() {
      const characterData = `$2`;
      const characters = parseCharacterData(characterData);
      const characterGrid = document.getElementById('characterGrid');

      characters.forEach(character => {
        const card = createCharacterCard(character);
        characterGrid.appendChild(card);
      });
    });
  </script>
</body>

</html>
