  <script type="module">
    // --- 辅助函数 ---
    function getMvuVal(data, path, defVal) {
      if (!data) return defVal;
      // 必须加上 stat_data 前缀
      const val = _.get(data, `stat_data.${path}`);
      if (val === undefined || val === null || val === 'null') return defVal;
      return val;
    }

    function getAttr(data, path) {
      const val = _.get(data, `stat_data.${path}`);
      if (!val) return { base: 0, total: 0 };
      return { base: val.base || 0, total: val.total || val.base || 0 };
    }

    // --- 渲染卡片生成器 ---
    function renderCard(type, data, slotName = null) {
      if (!data || data === 'null') {
        if (slotName) {
           return `<div class="item-card type-empty"><div class="item-header"><span class="item-name"><span class="slot-tag">${slotName}</span>空</span></div></div>`;
        }
        return '';
      }

      const name = data.name || '未命名';
      // 兼容旧数据（字符串）
      if (typeof data === 'string') {
         return `<div class="item-card type-${type}"><div class="item-header"><span class="item-name">${data}</span></div></div>`;
      }

      const desc = data.desc || '暂无简介';
      const effect = data.stats || data.effect || '无特殊效果';

      let rightContent = '';
      if (type === 'active') {
        const cur = data.current !== undefined ? data.current : '?';
        const max = data.max !== undefined ? data.max : '?';
        rightContent = `<span class="skill-uses">${cur}/${max}</span>`;
      } else if (type === 'equip' && data.magic_props) {
        rightContent = `<span class="skill-uses" style="color:var(--color-lapis);background:rgba(48,90,156,0.1)">法器</span>`;
      }

      let slotTag = slotName ? `<span class="slot-tag">${slotName}</span>` : '';

      return `
        <div class="item-card type-${type}">
          <div class="item-header">
            <span class="item-name">${slotTag}${name}</span>
            ${rightContent}
          </div>
          <div class="item-detail">
            <div class="item-desc">${desc}</div>
            <div class="item-effect">效果：${effect}</div>
          </div>
        </div>
      `;
    }

    // --- 主渲染函数 ---
    function populateCharacterData(mvuData) {
      if (!mvuData) return;

      // 1. 世界信息
      $('#world-display').text(
        `${getMvuVal(mvuData, 'World.Date', '未知日期')} ${getMvuVal(mvuData, 'World.Time', '')}`
      );
      $('#p-name').text(getMvuVal(mvuData, 'Player.Profile.Name', '无名氏'));
      $('#p-desc').text(
        `${getMvuVal(mvuData, 'Player.Profile.Race', '')} ${getMvuVal(mvuData, 'Player.Profile.Class', '')}`
      );

      // 2. 属性
      $('#val-valor').text(getAttr(mvuData, 'Player.Stats.Valor').total);
      $('#val-agility').text(getAttr(mvuData, 'Player.Stats.Agility').total);
      $('#val-spirit').text(getAttr(mvuData, 'Player.Stats.Spirit').total);

      // 3. 资源
      const hpCur = getMvuVal(mvuData, 'Player.Stats.HP.current', 0);
      const hpMax = getMvuVal(mvuData, 'Player.Stats.HP.max', 10);
      $('#val-hp-text').text(`${hpCur} / ${hpMax}`);
      const hpPct = Math.min(100, Math.max(0, (hpCur / hpMax) * 100));
      $('#val-hp-bar').css('width', `${hpPct}%`);

      $('#val-gold').text(getMvuVal(mvuData, 'Player.Resources.Gold', 0));
      $('#val-xp').text(getMvuVal(mvuData, 'Player.Resources.Exp', 0));
      $('#val-hpts').text(getMvuVal(mvuData, 'Player.Resources.HeroPoints', 0));

      // 4. 装备栏 (对象结构)
      const equipData = _.get(mvuData, 'stat_data.Player.Combat.Equipment', {});
      const slots = [
        { k: 'MainHand', n: '主手' }, { k: 'OffHand', n: '副手' }, { k: 'Body', n: '身体' },
        { k: 'Accessory1', n: '饰品' }, { k: 'Accessory2', n: '饰品' }, { k: 'Accessory3', n: '饰品' }
      ];

      let equipHtml = '';
      slots.forEach(slot => {
        const item = equipData[slot.k];
        equipHtml += renderCard('equip', item, slot.n);
      });
      $('#equip-list').html(equipHtml);

      // 5. 技能栏 (Record结构)
      const passiveRaw = _.get(mvuData, 'stat_data.Player.Combat.Skills.passive', {});
      const activeRaw = _.get(mvuData, 'stat_data.Player.Combat.Skills.active', {});

      let skillHtml = '';

      // 被动技能
      if (Array.isArray(passiveRaw)) {
         passiveRaw.forEach(s => skillHtml += renderCard('passive', { name: s }));
      } else {
         Object.entries(passiveRaw).forEach(([k, v]) => {
           skillHtml += renderCard('passive', { ...v, name: k });
         });
      }

      // 主动技能
      if (Array.isArray(activeRaw)) {
         activeRaw.forEach(s => {
           if(typeof s === 'string') {
             const [n, u] = s.split(':');
             const [c, m] = (u||'').split('/');
             skillHtml += renderCard('active', { name: n, current: c, max: m });
           }
         });
      } else {
         Object.entries(activeRaw).forEach(([k, v]) => {
           skillHtml += renderCard('active', { ...v, name: k });
         });
      }

      if (!skillHtml) skillHtml = '<div class="item-card type-empty" style="text-align:center;padding:10px;color:#999">尚未领悟任何技能</div>';
      $('#skill-list').html(skillHtml);

      // 6. 队友机制 (预留)
      const companions = getMvuVal(mvuData, 'Player.Companions', {}); // 假设路径
      let compHtml = '';
      if (companions && Object.keys(companions).length > 0) {
        Object.entries(companions).forEach(([k, v]) => {
           compHtml += `<div class="item-card type-passive"><div class="item-header"><span class="item-name">${v.name || k}</span></div></div>`;
        });
      } else {
        compHtml = '<div class="item-card type-empty" style="text-align:center;padding:10px;color:#999">尚无同行者</div>';
      }
      $('#comp-list').html(compHtml);
    }

    // --- 初始化 ---
    async function init() {
      try {
        // 自查要求：使用轮询确保MVU环境就绪
        let maxRetries = 50;
        while (typeof window.Mvu === 'undefined' && maxRetries > 0) {
          await new Promise(r => setTimeout(r, 100));
          maxRetries--;
        }
        if (typeof window.Mvu === 'undefined') {
          console.warn("MVU Plugin not found");
          $('#p-name').text("系统未就绪");
          return;
        }

        const data = await Mvu.getMvuData({ type: 'message', message_id: 'latest' });
        populateCharacterData(data);

        // 监听更新
        if (Mvu.events && Mvu.events.VARIABLE_UPDATE_ENDED) {
            // 注意：酒馆的 eventOn 是全局函数
            if (typeof eventOn === 'function') {
                eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, async () => {
                    const nData = await Mvu.getMvuData({ type: 'message', message_id: 'latest' });
                    populateCharacterData(nData);
                });
            }
        }
      } catch (e) {
        console.error("状态栏错误:", e);
        $('#p-name').text("加载异常");
      }
    }

    // 绑定交互事件
    $(document).on('click', '.item-card:not(.type-empty)', function() {
      $(this).find('.item-detail').slideToggle(150);
    });

    $(document).on('click', '.collapsible-header', function() {
      $(this).toggleClass('active');
      $(this).next('.collapsible-content').slideToggle(200);
    });

    // 启动
    $(document).ready(init);
  </script>
